#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int cmp(const void *a, const void *b) { return *(int*)a - *(int*)b; }

void backtrack(int *a, int n, int start, int *path, int pathLen,
               int subsets[][11], int *subsetSizes, int *cnt) {
    // store current subset
    memcpy(subsets[*cnt], path, pathLen * sizeof(int));
    subsetSizes[*cnt] = pathLen;
    (*cnt)++;
    for (int i = start; i < n; ++i) {
        if (i > start && a[i] == a[i-1]) continue; // skip duplicates
        path[pathLen] = a[i];
        backtrack(a, n, i + 1, path, pathLen + 1, subsets, subsetSizes, cnt);
    }
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int a[10];
        for (int i = 0; i < n; ++i) scanf("%d", &a[i]);
        qsort(a, n, sizeof(int), cmp);
        int subsets[1024][11]; // max 2^10 subsets, each up to 10 elements
        int subsetSizes[1024];
        int cnt = 0;
        int path[10];
        backtrack(a, n, 0, path, 0, subsets, subsetSizes, &cnt);
        // print result
        printf("[");
        for (int i = 0; i < cnt; ++i) {
            printf("[");
            for (int j = 0; j < subsetSizes[i]; ++j) {
                printf("%d", subsets[i][j]);
                if (j + 1 < subsetSizes[i]) printf(", ");
            }
            printf("]");
            if (i + 1 < cnt) printf(", ");
        }
        printf("]");
        if (T) printf("\n");
    }
    return 0;
}

