#include <bits/stdc++.h>
using namespace std;

void backtrack(const vector<int>& a, int start, vector<int>& path, vector<vector<int>>& res) {
    res.push_back(path);
    for (int i = start; i < (int)a.size(); ++i) {
        if (i > start && a[i] == a[i-1]) continue; // skip duplicates
        path.push_back(a[i]);
        backtrack(a, i + 1, path, res);
        path.pop_back();
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    while (T--) {
        int n; cin >> n;
        vector<int> a(n);
        for (int &x : a) cin >> x;
        sort(a.begin(), a.end());
        vector<vector<int>> subsets;
        vector<int> path;
        backtrack(a, 0, path, subsets);
        cout << "[";
        for (size_t i = 0; i < subsets.size(); ++i) {
            cout << "[";
            for (size_t j = 0; j < subsets[i].size(); ++j) {
                cout << subsets[i][j];
                if (j + 1 < subsets[i].size()) cout << ", ";
            }
            cout << "]";
            if (i + 1 < subsets.size()) cout << ", ";
        }
        cout << "]";
        if (T) cout << '\n';
    }
    return 0;
}

