import java.io.*;
import java.util.*;

public class Main {
    private static void backtrack(int[] a, int start, List<Integer> path, List<List<Integer>> res) {
        res.add(new ArrayList<>(path));
        for (int i = start; i < a.length; i++) {
            if (i > start && a[i] == a[i - 1]) continue; // skip duplicates
            path.add(a[i]);
            backtrack(a, i + 1, path, res);
            path.remove(path.size() - 1);
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int n = Integer.parseInt(br.readLine().trim());
            st = new StringTokenizer(br.readLine());
            int[] a = new int[n];
            for (int i = 0; i < n; i++) a[i] = Integer.parseInt(st.nextToken());
            Arrays.sort(a);
            List<List<Integer>> subsets = new ArrayList<>();
            backtrack(a, 0, new ArrayList<>(), subsets);
            out.append('[');
            for (int i = 0; i < subsets.size(); i++) {
                out.append('[');
                List<Integer> sub = subsets.get(i);
                for (int j = 0; j < sub.size(); j++) {
                    out.append(sub.get(j));
                    if (j + 1 < sub.size()) out.append(", ");
                }
                out.append(']');
                if (i + 1 < subsets.size()) out.append(", ");
            }
            out.append(']');
            if (tc + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

