const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let out = [];
function backtrack(arr, start, path, res) {
    res.push(path.slice());
    for (let i = start; i < arr.length; i++) {
        if (i > start && arr[i] === arr[i-1]) continue; // skip duplicates
        path.push(arr[i]);
        backtrack(arr, i + 1, path, res);
        path.pop();
    }
}
for (let tc = 0; tc < T; tc++) {
    const n = input[idx++];
    const arr = input.slice(idx, idx + n);
    idx += n;
    arr.sort((a, b) => a - b);
    const subsets = [];
    backtrack(arr, 0, [], subsets);
    const parts = subsets.map(sub => '[' + sub.join(', ') + ']');
    out.push('[' + parts.join(', ') + ']');
}
console.log(out.join('\n'));

